{
  "sentences": [
    {
      "text": "我現在每天中午吃午餐。",
      "pinyin": "Wǒ xiànzài měitiān zhōngwǔ chī wǔcān.",
      "pinyin_numeric": "wo3 xian4zai4 mei3tian1 zhong1wu3 chi1 wu3can1.",
      "translation_en": "I now eat lunch every day at noon.",
      "translation_ko": "저는 지금 매일 점심에 점심을 먹습니다."
    },
    {
      "text": "他現在晚上看電視。",
      "pinyin": "Tā xiànzài wǎnshàng kàn diànshì.",
      "pinyin_numeric": "ta1 xian4zai4 wan3shang4 kan4 dian4shi4.",
      "translation_en": "He watches TV in the evening now.",
      "translation_ko": "그는 지금 저녁에 텔레비전을 봅니다."
    },
    {
      "text": "我們現在早上刷牙洗臉。",
      "pinyin": "Wǒmen xiànzài zǎoshàng shuāyá xǐliǎn.",
      "pinyin_numeric": "wo3men0 xian4zai4 zao3shang4 shua1ya2 xi3lian3.",
      "translation_en": "We brush our teeth and wash our face in the morning now.",
      "translation_ko": "우리는 지금 아침에 이를 닦고 세수합니다."
    },
    {
      "text": "她現在下午上班。",
      "pinyin": "Tā xiànzài xiàwǔ shàngbān.",
      "pinyin_numeric": "ta1 xian4zai4 xia4wu3 shang4ban1.",
      "translation_en": "She goes to work in the afternoon now.",
      "translation_ko": "그녀는 지금 오후에 출근합니다."
    },
    {
      "text": "我現在晚上做功課。",
      "pinyin": "Wǒ xiànzài wǎnshàng zuò gōngkè.",
      "pinyin_numeric": "wo3 xian4zai4 wan3shang4 zuo4 gong1ke4.",
      "translation_en": "I do homework in the evening now.",
      "translation_ko": "저는 지금 저녁에 숙제를 합니다."
    },
    {
      "text": "他現在中午休息。",
      "pinyin": "Tā xiànzài zhōngwǔ xiūxí.",
      "pinyin_numeric": "ta1 xian4zai4 zhong1wu3 xiu1xi2.",
      "translation_en": "He rests at noon now.",
      "translation_ko": "그는 지금 점심에 휴식합니다."
    },
    {
      "text": "我們現在早上吃早餐。",
      "pinyin": "Wǒmen xiànzài zǎoshàng chī zǎocān.",
      "pinyin_numeric": "wo3men0 xian4zai4 zao3shang4 chi1 zao3can1.",
      "translation_en": "We eat breakfast in the morning now.",
      "translation_ko": "우리는 지금 아침에 아침을 먹습니다."
    },
    {
      "text": "她現在晚上聽音樂。",
      "pinyin": "Tā xiànzài wǎnshàng tīng yīnyuè.",
      "pinyin_numeric": "ta1 xian4zai4 wan3shang4 ting1 yin1yue4.",
      "translation_en": "She listens to music in the evening now.",
      "translation_ko": "그녀는 지금 저녁에 음악을 듣습니다."
    },
    {
      "text": "我現在下午看書。",
      "pinyin": "Wǒ xiànzài xiàwǔ kàn shū.",
      "pinyin_numeric": "wo3 xian4zai4 xia4wu3 kan4 shu1.",
      "translation_en": "I read books in the afternoon now.",
      "translation_ko": "저는 지금 오후에 책을 봅니다."
    },
    {
      "text": "他現在晚上散步。",
      "pinyin": "Tā xiànzài wǎnshàng sànbù.",
      "pinyin_numeric": "ta1 xian4zai4 wan3shang4 san4bu4.",
      "translation_en": "He takes a walk in the evening now.",
      "translation_ko": "그는 지금 저녁에 산책합니다."
    }
  ]
}
